   146→function NotificationsCard() {
   147→  const { data: userSettings, isLoading } = useUserSettings();
   148→  const updateMutation = useUpdateUserSettings();
   149→  const debounceRef = useRef<NodeJS.Timeout | null>(null);
   150→
   151→  const notif = userSettings?.[UserSetting.Notifications] ?? null;
   152→
   153→  const handleToggle = useCallback(
   154→    (field: keyof UserNotificationsSetting, value: boolean) => {
   155→      if (!notif) return;
   156→      if (debounceRef.current) clearTimeout(debounceRef.current);
   157→      debounceRef.current = setTimeout(() => {
   158→        updateMutation.mutate(
   159→          { [UserSetting.Notifications]: { ...notif, [field]: value } },
   160→          {
   161→            onSuccess: () => toast.success("Settings updated"),
   162→            onError: () => toast.error("Failed to update settings"),
   163→          },
   164→        );
   165→      }, 300);
   166→    },
   167→    [notif, updateMutation],
   168→  );
   169→
   170→  const items: {
   171→    field: keyof UserNotificationsSetting;
   172→    icon: ReactNode;
   173→    title: string;
   174→    description: string;
   175→  }[] = [
   176→    {
   177→      field: "general",
   178→      icon: <BellRing className="h-4 w-4 shrink-0 text-[#78716C]" />,
   179→      title: "General Notification",
   180→      description: "Enable all Notification for Updates and Alerts",
   181→    },
