   192→      description: "Notifications for login attempts, password changes",
   193→    },
   194→  ];
   195→
   196→  return (
   197→    <SettingsCard>
   198→      <CardHeader title="Notification settings" />
   199→
   200→      <div className="flex flex-col divide-y divide-[#E7E5E4]">
   201→        {isLoading
   202→          ? [1, 2, 3].map((i) => (
   203→              <div
   204→                key={i}
   205→                className="h-14 animate-pulse bg-[#F5F3EF] first:rounded-t-xl last:rounded-b-xl"
   206→              />
   207→            ))
   208→          : items.map(({ field, icon, title, description }) => (
   209→              <div
   210→                key={field}
   211→                className="flex items-center gap-3 py-3 first:pt-0 last:pb-0"
   212→              >
   213→                {icon}
   214→                <div className="flex flex-1 flex-col">
