   216→                    {title}
   217→                  </span>
   218→                  <span className="font-new-sans text-xs text-[#A8A29E]">
   219→                    {description}
   220→                  </span>
   221→                </div>
   222→                <Switch
   223→                  disabled={!notif}
   224→                  checked={notif?.[field] ?? false}
   225→                  onCheckedChange={(value) => handleToggle(field, value)}
   226→                />
   227→              </div>
   228→            ))}
   229→      </div>
   230→    </SettingsCard>
   231→  );
   232→}
