     1→"use client";
     2→
     3→import { useInitiateKyc } from "@/entities/kyc";
     4→import { ApiKeys } from "@/shared/api/query-keys";
     5→import { APP_ROUTES } from "@/shared/config/app-routes";
     6→import { ENV } from "@/shared/config/env";
     7→import { Button } from "@/shared/ui/button";
     8→import { toast } from "@/shared/ui/notification";
     9→import { loadStripe } from "@stripe/stripe-js";
    10→import { useQueryClient } from "@tanstack/react-query";
    11→import { useRouter } from "next/navigation";
    12→import { useState } from "react";
    13→
    14→const stripePromise = loadStripe(ENV.NEXT_PUBLIC_STRIPE_PUBLISHABLE_KEY);
    15→
    16→interface StripeIdentityVerificationProps {
    17→  onClose?: () => void;
    18→}
    19→
    20→export function StripeIdentityVerification({
    21→  onClose,
    22→}: StripeIdentityVerificationProps) {
    23→  const router = useRouter();
    24→  const [isLoading, setIsLoading] = useState(false);
    25→  const { mutateAsync: initiateKyc } = useInitiateKyc();
    26→  const queryClient = useQueryClient();
    27→
    28→  async function handleStartVerification() {
    29→    try {
    30→      setIsLoading(true);
    31→
    32→      const { clientSecret } = await initiateKyc();
    33→
    34→      const stripe = await stripePromise;
    35→
    36→      if (!stripe) {
    37→        throw new Error("Stripe not loaded");
    38→      }
    39→
    40→      const { error } = await stripe.verifyIdentity(clientSecret);
    41→
    42→      if (error) {
    43→        toast.error(error.message || "Failed to start verification");
    44→        return;
    45→      }
    46→
    47→      toast.success("Verification started successfully");
    48→      onClose?.();
    49→      queryClient.removeQueries({
    50→        queryKey: ApiKeys.kycStatus(),
    51→      });
    52→      router.push(APP_ROUTES.KYC.RETURN);
    53→    } catch (error) {
    54→      toast.error("Failed to initiate KYC verification");
    55→      console.error("KYC initiation error:", error);
    56→    } finally {
    57→      setIsLoading(false);
    58→    }
    59→  }
    60→
    61→  return (
    62→    <div className="flex w-full flex-col items-center gap-5">
    63→      <div className="flex w-full flex-col gap-2.5">
    64→        <h3 className="font-bold font-serif text-lg leading-[1.199em]">
    65→          Verify Your Identity
    66→        </h3>
    67→        <p className="font-serif text-base leading-[1.199em]">
    68→          To comply with regulatory requirements and ensure platform security,
    69→          we need to verify your identity. This process is quick and secure,
    70→          powered by Stripe Identity.
    71→        </p>
    72→      </div>
    73→
    74→      <div className="flex w-full flex-col gap-3 rounded-input bg-[#E5F2F0] p-5">
    75→        <p className="font-bold font-serif text-sm leading-[1.199em]">
    76→          What you'll need:
    77→        </p>
    78→        <ul className="list-inside list-disc space-y-1 font-serif text-sm leading-[1.199em]">
    79→          <li>
    80→            A valid government-issued ID (passport, driver's license, or
    81→            national ID)
    82→          </li>
    83→          <li>Your phone or computer with a camera</li>
    84→          <li>Good lighting for clear photos</li>
    85→          <li>5-10 minutes to complete the process</li>
    86→        </ul>
    87→      </div>
    88→
    89→      <Button
    90→        type="button"
    91→        onClick={handleStartVerification}
    92→        loading={isLoading}
    93→        disabled={isLoading}
    94→        className="w-full"
    95→      >
    96→        Start Verification
    97→      </Button>
    98→    </div>
    99→  );
   100→}
