    12→export default function SidebarLayout({ children }: { children: ReactNode }) {
    13→  const router = useRouter();
    14→  const pathname = usePathname();
    15→  const { isOpen, setIsOpen } = useSidebarContext();
    16→
    17→  function getActiveItem() {
    18→    for (const item of SELLER_SIDEBAR_ITEMS) {
    19→      if (item.path === pathname) {
    20→        return item.value;
    21→      }
    22→
    23→      if (item.subItems) {
    24→        for (const subItem of item.subItems) {
    25→          if (subItem.path === pathname) {
    26→            return subItem.value;
    27→          }
    28→        }
    29→      }
    30→    }
    31→
    32→    for (const item of SELLER_SIDEBAR_ITEMS) {
    33→      if (item.subItems) {
    34→        for (const subItem of item.subItems) {
    35→          const basePath = subItem.path.split("?")[0];
    36→          if (
    37→            pathname.startsWith(basePath) &&
    38→            (pathname[basePath.length] === "?" ||
    39→              pathname[basePath.length] === "/" ||
    40→              pathname.length === basePath.length)
    41→          ) {
    42→            return subItem.value;
    43→          }
    44→        }
    45→      }
    46→    }
    47→
    48→    const firstSegment = pathname.split("/")[1];
    49→
    50→    return firstSegment || "profile";
    51→  }
    52→
    53→  const activeItem = getActiveItem();
    54→
    55→  async function handleItemClick(value: string, path?: string) {
    56→    if (value === "logout") {
    57→      await signOut({ redirect: false });
    58→      router.push(APP_ROUTES.AUTH.SIGN_IN);
    59→      router.refresh();
    60→
    61→      return;
    62→    }
    63→
    64→    if (path && path !== "#") {
    65→      router.push(path);
    66→    }
    67→  }
    68→
    69→  const isFullWidthPage = pathname === APP_ROUTES.PROFILE;
    70→
    71→  if (isFullWidthPage) {
    72→    return <>{children}</>;
    73→  }
    74→
    75→  return (
    76→    <div className="flex min-h-full w-full flex-col md:flex-row">
    77→      <Sidebar
    78→        items={SELLER_SIDEBAR_ITEMS}
    79→        activeItem={activeItem}
    80→        onItemClick={handleItemClick}
    81→        isOpen={isOpen}
    82→        onOpenChange={setIsOpen}
    83→      />
    84→      <div className="flex-1 px-3 pt-4 pb-6 sm:px-4 sm:pt-8 lg:max-w-[calc(100vw-266px)] lg:pt-8">
    85→        {children}
    86→      </div>
    87→    </div>
